#include <bits/stdc++.h>
using namespace std;

int main() {
    int n, m, rel[1005][1005], ans1 = 0, ans2 = 0;
    cin >> n >> m;
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n; j++) {
            cin >> rel[i][j];
        }
    }
    for (int i = 0; i < n; i++) {
        if (rel[m - 1][i] == 1) {
            ans1++;
        }
        if (rel[i][m - 1] == 1) {
            ans2++;
        }
    }
    printf("%d %d %d\n", ans1, ans2, ans1 + ans2);
    return 0;
}
